const topic = String(msg.topic || "");
const match = /^req\/([^/]+)\/ui-profile$/.exec(topic);

if (!match) {
    node.warn("Ignoring malformed UI profile topic: " + topic);
    return null;
}

const stationid = String(match[1] || "").trim();
if (!stationid || !/^[A-Za-z0-9._-]{1,120}$/.test(stationid)) {
    node.warn("Ignoring invalid station id");
    return null;
}

const request = msg.payload && typeof msg.payload === "object"
    ? msg.payload
    : {};
const resolveUrl = env.get("UI_PROFILE_RESOLVE_URL");
const token = env.get("UI_PROFILE_API_TOKEN");

if (!resolveUrl || !token) {
    node.error("UI_PROFILE_RESOLVE_URL or UI_PROFILE_API_TOKEN is not configured", msg);
    return null;
}

msg.stationid = stationid;
msg.responseTopic = "res/" + stationid + "/ui-profile";
msg.profileRequest = {
    currentProfileId: String(request.currentProfileId || ""),
    currentProfileVersion: Number(request.currentProfileVersion || 0),
    currentProfileHash: String(request.currentProfileHash || "")
};
msg.method = "POST";
msg.url = resolveUrl;
msg.headers = {
    "content-type": "application/json",
    "authorization": "Bearer " + token
};
msg.payload = JSON.stringify({
    stationid,
    currentProfileId: msg.profileRequest.currentProfileId,
    currentProfileVersion: msg.profileRequest.currentProfileVersion,
    currentProfileHash: msg.profileRequest.currentProfileHash
});

node.status({ fill: "blue", shape: "dot", text: "lookup " + stationid });
return msg;

const stationid = String(msg.stationid || "");
const request = msg.profileRequest || {};
let body = msg.payload;

if (typeof body === "string") {
    try { body = JSON.parse(body); } catch (error) { body = {}; }
}

// Supports both a direct HTTP response and a Firebase-style { result: ... } response.
const resolved = body && typeof body === "object"
    ? (body.result || body.data || body)
    : {};
const profileId = String(resolved.profileId || resolved.id || "");
const profileVersion = Number(resolved.profileVersion || resolved.version || 0);
const profileHash = String(resolved.profileHash || resolved.hash || "");
const colors = resolved.colors || resolved.ui?.colors;
const languages = resolved.languages;

msg.topic = msg.responseTopic || ("res/" + stationid + "/ui-profile");
msg.qos = 1;
msg.retain = false;

if (Number(msg.statusCode || 200) >= 400 || resolved.ok === false) {
    msg.payload = {
        status: "error",
        code: String(resolved.code || "profile_lookup_failed"),
        message: String(resolved.message || "Could not resolve active UI profile")
    };
    node.status({ fill: "red", shape: "ring", text: stationid + " lookup failed" });
    return msg;
}

if (!profileId || !profileVersion) {
    msg.payload = {
        status: "error",
        code: "no_active_profile",
        message: "No active UI profile is assigned to this kiosk client"
    };
    node.status({ fill: "yellow", shape: "ring", text: stationid + " no profile" });
    return msg;
}

const isCurrent =
    request.currentProfileId === profileId &&
    Number(request.currentProfileVersion || 0) === profileVersion &&
    (!profileHash || request.currentProfileHash === profileHash);

if (isCurrent) {
    msg.payload = {
        status: "current",
        profileId,
        profileVersion,
        profileHash
    };
    node.status({ fill: "green", shape: "dot", text: stationid + " current v" + profileVersion });
    return msg;
}

if (!colors || !languages) {
    msg.payload = {
        status: "error",
        code: "invalid_profile_payload",
        message: "Resolved profile is missing colors or languages"
    };
    node.status({ fill: "red", shape: "ring", text: stationid + " invalid profile" });
    return msg;
}

msg.payload = {
    status: "update",
    profileId,
    profileVersion,
    profileHash,
    colors: {
        bcolor1: String(colors.bcolor1 || "#078B8C").toUpperCase(),
        bcolor2: String(colors.bcolor2 || "#131E3A").toUpperCase()
    },
    languages
};
node.status({ fill: "green", shape: "dot", text: stationid + " update v" + profileVersion });
return msg;

const topic = String(msg.topic || "");
const match = /^ack\/([^/]+)\/ui-profile$/.exec(topic);
if (!match) return null;

const stationid = String(match[1] || "").trim();
const ack = msg.payload && typeof msg.payload === "object"
    ? msg.payload
    : {};
const ackUrl = env.get("UI_PROFILE_ACK_URL");
const token = env.get("UI_PROFILE_API_TOKEN");

if (!ackUrl || !token || !stationid) {
    node.error("UI profile acknowledgement endpoint is not configured", msg);
    return null;
}

msg.method = "POST";
msg.url = ackUrl;
msg.headers = {
    "content-type": "application/json",
    "authorization": "Bearer " + token
};
msg.payload = JSON.stringify({
    stationid,
    profileId: String(ack.profileId || ""),
    profileVersion: Number(ack.profileVersion || 0),
    profileHash: String(ack.profileHash || ""),
    status: String(ack.status || "applied"),
    appliedAt: String(ack.appliedAt || new Date().toISOString()),
    error: String(ack.error || "")
});
node.status({ fill: "blue", shape: "dot", text: "ack " + stationid });
return msg;

if (Number(msg.statusCode || 200) >= 400) {
    node.status({ fill: "red", shape: "ring", text: "ack failed" });
    node.warn(msg.payload);
    return null;
}
node.status({ fill: "green", shape: "dot", text: "ack saved" });
return null;
